+                        Pdu::SetClientId(_) => {
+                            write_mux_response(
+                                &mut stream,
+                                decoded.serial,
+                                Pdu::UnitResponse(UnitResponse {}),
+                            )
+                            .await;
+                        }
+                        Pdu::GetPaneRenderChanges(request) => {
+                            batch_requests_seen += 1;
+                            if batch_requests_seen == 1 {
+                                write_mux_response(
+                                    &mut stream,
+                                    decoded.serial,
+                                    Pdu::GetPaneRenderChangesResponse(
+                                        GetPaneRenderChangesResponse {
+                                            pane_id: request.pane_id,
+                                            mouse_grabbed: false,
+                                            cursor_position:
