+                                            working_dir: None,
+                                            bonus_lines: Vec::new().into(),
+                                            input_serial: None,
+                                            seqno: 1,
+                                        },
+                                    ),
+                                )
+                                .await;
+                            } else {
+                                runtime_compat::sleep(Duration::from_millis(150)).await;
+                                return batch_requests_seen;
+                            }
+                        }
+                        other => panic!("unexpected handshake/request PDU: {}", other.pdu_name()),
